// src/App.js
import React, { useState, useEffect } from "react";
import { onAuthStateChanged, signOut } from "firebase/auth";
import { auth } from "./utils/firebase";
import LandingPage from "./pages/LandingPage";
import Practice    from "./pages/PracticePage";
import Results     from "./pages/ResultsPage";
import Dashboard   from "./pages/DashboardPage";
import "./App.css";

export default function App() {
  const [page, setPage]         = useState("landing");
  const [scenario, setScenario] = useState(null);
  const [result, setResult]     = useState(null);
  const [user, setUser]         = useState(null);
  const [authReady, setAuthReady] = useState(false);

  // Listen for Firebase auth state changes
  useEffect(() => {
    const unsub = onAuthStateChanged(auth, (u) => {
      setUser(u);
      setAuthReady(true);
    });
    return unsub;
  }, []);

  const navigate = (to, data = {}) => {
    if (data.scenario) setScenario(data.scenario);
    if (data.result)   setResult(data.result);
    setPage(to);
  };

  const handleLogout = async () => {
    await signOut(auth);
    setPage("landing");
  };

  if (!authReady) {
    // Minimal splash while Firebase checks auth
    return (
      <div style={{
        minHeight: "100vh", display: "flex",
        alignItems: "center", justifyContent: "center",
        background: "#0F0F1A"
      }}>
        <div style={{
          fontFamily: "var(--font-display, sans-serif)",
          fontSize: 28, fontWeight: 800, letterSpacing: 2,
          background: "linear-gradient(135deg,#a29bfe,#00cec9)",
          WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent"
        }}>
          CLARIO
        </div>
      </div>
    );
  }

  return (
    <div className="app-root">
      {page === "landing" && (
        <LandingPage navigate={navigate} user={user} onLogout={handleLogout} />
      )}
      {page === "practice" && (
        <Practice scenario={scenario} onNavigate={navigate} />
      )}
      {page === "results" && (
        <Results result={result} scenario={scenario} onNavigate={navigate} />
      )}
      {page === "dashboard" && (
        <Dashboard onNavigate={navigate} />
      )}
    </div>
  );
}
